170	
171	    #[test]
172	    fn is_builtin_excluded_target_dir_excluded() {
173	        assert!(is_builtin_excluded(Path::new("target/release/drywall")));
174	        assert!(is_builtin_excluded(Path::new("proj/target/foo.rs")));
175	    }
176	
177	    #[test]
178	    fn is_builtin_excluded_all_seven_names() {
179	        for name in &[
180	            ".git",
181	            "target",
182	            "node_modules",
183	            "__pycache__",
184	            "vendor",
185	            "dist",
186	            ".next",
187	        ] {
188	            let p = Path::new(name).join("file.rs");
189	            assert!(is_builtin_excluded(&p), "{} should be excluded", name);
190	        }
191	    }
192	
193	    #[test]
194	    fn is_builtin_excluded_nested_at_any_depth() {
195	        assert!(is_builtin_excluded(Path::new("a/b/c/node_modules/d/e.rs")));
196	    }
197	
198	    #[test]
199	    fn is_builtin_excluded_non_excluded_path_passes() {
200	        assert!(!is_builtin_excluded(Path::new("src/lib.rs")));
201	        assert!(!is_builtin_excluded(Path::new("src/core.rs")));
202	    }
203	
204	    #[test]
205	    fn is_builtin_excluded_partial_name_does_not_match() {
206	        // "targets" or "my_target" must NOT be excluded
207	        assert!(!is_builtin_excluded(Path::new("targets/foo.rs")));
208	        assert!(!is_builtin_excluded(Path::new("my_target/foo.rs")));
209	    }
210	
211	    #[test]
212	    fn collect_from_directory_skips_builtin_excluded_dirs() {
213	        let dir = tempfile::tempdir().unwrap();
214	        let target_dir = dir.path().join("target");
215	        std::fs::create_dir_all(&target_dir).unwrap();
216	        let body = r#"pub fn accumulate_sum(a: i32, b: i32) -> i32 {
217	    let sum = a + b;
218	    let extra = sum * 2;
219	    let more = extra + a;
220	    let result = more + b;
221	    result
222	}
223	"#;
224	        std::fs::write(target_dir.join("excluded.rs"), body).unwrap();
225	        std::fs::write(dir.path().join("keep.rs"), body).unwrap();
226	        let gs = build_glob_set(&[]).unwrap();
